205	    /// path. In other words, we want the compiler to optimize branching for the case when
206	    /// `collect()` is not called.
207	    #[cold]
208	    pub(crate) fn collect(&self, guard: &Guard) {
209	        let global_epoch = self.try_advance(guard);
210	
211	        let steps = if cfg!(crossbeam_sanitize) {
212	            usize::MAX
213	        } else {
214	            Self::COLLECT_STEPS
215	        };
216	
217	        for _ in 0..steps {
